-- -----------------------------------------------------------------------------
-- F. Verification (run AFTER commit). Expected on top of a clean original seed:
--      schools          = 3
--      parents          = 29  (11 original + 6 s1/s2-new + 12 s3)
--      teachers         = 21  (7 original + 4 s1/s2-new + 10 s3)
--      children         = 33  (15 original + 6 s1/s2-new + 14 s3-child rows)
--    (>= if you seeded extra elsewhere; never less.)
-- -----------------------------------------------------------------------------
SELECT 'schools'  AS entity, count(*) AS n FROM public.schools
UNION ALL SELECT 'parents',  count(*) FROM public.app_users WHERE role='parent'
UNION ALL SELECT 'teachers', count(*) FROM public.app_users WHERE role='teacher'
UNION ALL SELECT 'admins',   count(*) FROM public.app_users WHERE role='school_admin'
UNION ALL SELECT 'students', count(*) FROM public.students
UNION ALL SELECT 'children', count(*) FROM public.children
UNION ALL SELECT 'subjects', count(*) FROM public.school_subjects;

-- Tenancy invariant: every parent must have school_id NULL (OTP-signup state).
SELECT 'BAD_parent_tenancy' AS check, count(*) AS n
FROM public.app_users WHERE role='parent' AND school_id IS NOT NULL;

